import myOpenGL     from '../../myOpenGL.js'

// Hàm đọc file JSON (có thể bỏ vào DialogueAPI hoặc js_glue.js)
const LoadIngredientsDB = async function(_f) {
  try {
    const response = await fetch(`${_f}?t=${Date.now()}`);
    const data = await response.json();
    return data;
  } catch (err) {
    console.error("❌ Lỗi nạp dữ liệu nguyên liệu:", err);
    return [];
  }
};

async function reload_shader(food_name) {
  if(!window.DialogueAPI._currentCanvas) return;
  const gl = window.DialogueAPI._currentCanvas;
  // const fragSrc = window._codeditor.getValue();

  try {
    // Fetch shader source
    const response = await fetch("./resources/mathNote/shader/frag_cook.glsl");
    if (!response.ok) {
      // Throwing an error here is identical to calling reject()
      throw new Error(`HTTP error! Shader fetch failed: ${response.status}`);
    }
    const fragSrc = await response.text();

    // Dynamic import image
    const imageModule = await import(`/resources/items/ingredients_${food_name}.png`);
    const actualImageElement = await window.App.loadImage(imageModule.default);
    gl.fLoadTexture("tex001", actualImageElement, true);

    // 1. DỌN RÁC (MEMORY MANAGEMENT)
    // Nếu Wrapper của bạn có hàm hủy thì gọi nó (VD: gl.gShader.destroy())
    // Nếu không, hãy gọi thẳng API của WebGL để xóa Program cũ:
    if (gl.gShader && gl.gShader.program) {
      gl.deleteProgram(gl.gShader.program); 
      console.log("🗑️ Đã xóa Shader cũ an toàn");
    }

    // 2. BIÊN DỊCH SHADER MỚI
    gl.gShader = new myOpenGL.ThuyShader(gl, gl.gCamera.projectionMatrix, fragSrc)
      .activate()
      .setTexture(gl.mTextureCache["tex001"], "uMainTex");
    console.log("✅ Cập nhật Shader thành công!");

  } catch (err) {
    // Bắt lỗi nếu người dùng gõ code GLSL sai (rất hay xảy ra khi live-coding)
    console.error("❌ Lỗi biên dịch Shader:", err);
  }
}

// Helper function to update shader
function updateShaderOffset(item) {
  if(!window.DialogueAPI._currentCanvas) return;
  const gl = window.DialogueAPI._currentCanvas;
  const x = item.col;
  const y = item.row; 
  gl.gShader.activate().setI('u_full', 0);
  gl.gShader.activate().setVec2('u_offset', x, y);
}

